// ─── Translation lookup function ─────────────────────────────────────────────
export function getT(lang) {
  return function t(key, params = {}) {
    const entry = T[key];
    if (!entry) return key;
    let str = entry[lang] || entry['hinglish'] || key;
    Object.entries(params).forEach(([k, v]) => {
      str = str.replace(new RegExp(`\\{${k}\\}`, 'g'), v);
    });
    return str;
  };
}

export default T;
